files={
'Action Items':'a20641fc835dda67d3eb92f561f59724405b69fe81962c183565d304d577be61.json',
'Todo':'bebd6a23fa2db170880b399763e7e86dcbaf6b8c48b71f4523212caa4a51b679.json',
'Sentry issue':'e365f5a4760c222e9c53606e743796cba42220a8f86df58b16092097b1ac0ce1.json',
'slow api':'692f446e25bcb347bca9c5af8007b3d1a3020434ba2390093bb0dc93ea30a00b.json',
'PRD':'7c915f97a5115d32ce9198718eb1aedf5525be0474c579ce4c3b25aed2b8af98.json',
'회의록':'b1bfacc50d5b2941745f0fe7b901d9cf99700c4a6f2ea5c87d06708655d26775.json'}

def parse_title(props):
    for k,v in props.items():
        if v.get('type')=='title':
            return ''.join(t.get('plain_text','') for t in v.get('title',[])).strip()
    return ''

def prop_val(v):
    t=v.get('type')
    if t in ('status','select'):
        return (v.get(t) or {}).get('name')
    if t=='date':
        return (v.get('date') or {}).get('start')
    if t=='checkbox':
        return v.get('checkbox')
    return None

for name,f in files.items():
    d=json.load(open(root/f))['payload']
    rows=d['results']
    # sort recent
    rows_sorted=sorted(rows,key=lambda r:r.get('last_edited_time') or '', reverse=True)
    print('\n##',name,'fetched_at',d['fetched_at'],'rows',len(rows))
    # status counts
    status_counts={}
    for r in rows:
        for k,v in r.get('properties',{}).items():
            if v.get('type')=='status':
                nm=(v.get('status') or {}).get('name') or 'None'
                status_counts[nm]=status_counts.get(nm,0)+1
    if status_counts:
        print('status_counts',status_counts)
    for r in rows_sorted[:10]:
        props=r.get('properties',{})
        title=parse_title(props)
        info=[]
        for k in ['Status','완료여부','Due Date','날짜','담당자','Assignee','우선 순위','Priority']:
            if k in props:
                val=prop_val(props[k])
                if val not in (None,''):
                    info.append(f'{k}={val}')
        print(r.get('last_edited_time'), '|', title[:80], '|', '; '.join(info))
